// Generated by Cypress Author — 2026-05-16
// Fixed: 2026-05-16 — stub create/list APIs for happy path & duplicate tests;
// correct whitespace behavior (Zod min(1) allows whitespace, API rejects it);
// form reset on cancel now works after AddProductBrand.jsx fix.

import { faker } from '@faker-js/faker'

// Stub the POST create endpoint with a preset response
const stubCreateSuccess = (brandName, brandId) => {
  cy.intercept('POST', '/api/inventory/v1/product-brand/create', {
    statusCode: 201,
    body: {
      success: true,
      productBrand: {
        id: brandId,
        brand: brandName,
        brand_status: 'active',
        note: '',
        user_id: 'test-user',
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        deleted_at: null,
        product_count: 0,
      },
    },
  }).as('createBrand')
}

// Stub the list refresh so the table re-renders after a create
const stubListWithBrand = (brandName, brandId) => {
  cy.intercept('GET', '/api/inventory/v1/product-brand/list', {
    statusCode: 200,
    body: {
      success: true,
      data: [
        {
          id: brandId,
          brand: brandName,
          brand_status: 'active',
          note: '',
          user_id: 'test-user',
          created_at: new Date().toISOString(),
          updated_at: new Date().toISOString(),
          deleted_at: null,
          product_count: 0,
        },
      ],
    },
  }).as('listBrands')
}

describe('Add Product Brand - UI Tests', () => {
  // ------------------------------------------------------------------
  // Happy Path: new row appears after successful submission
  // ------------------------------------------------------------------
  describe('Happy Path - new brand appears in table', () => {
    beforeEach(() => {
      cy.viewport(1280, 720)
      cy.setupApiAuthCookies()
      cy.visit('/main/inventory/product-brand')
      cy.wait(1000)
    })

    it('should add a new brand → new row appears in the table', () => {
      const brandId = 9001
      const createdBrandName = 'ADD-' + faker.string.alphanumeric(10)

      stubCreateSuccess(createdBrandName, brandId)
      stubListWithBrand(createdBrandName, brandId)

      cy.get('#addNewProductBrandBtn_desktop_productBrandPage').filter(':visible').click()
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('be.visible')

      cy.get('#brandNameInput_addBrandDialog').type(createdBrandName)
      cy.get('#submitNewProductBrandBtn_productBrandPage').click()

      // Wait for the stubbed API call
      cy.wait('@createBrand')

      // Dialog should close after successful submission
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('not.exist')

      // The new brand row should appear in the table (from the stubbed list response)
      cy.get('#productBrandsTable_productBrandPage').should('contain', createdBrandName)
    })

    it('should add a brand with a note → dialog closes and brand visible', () => {
      const brandId = 9002
      const createdBrandName = 'ADD-NOTE-' + faker.string.alphanumeric(8)
      const note = faker.word.words(4)

      stubCreateSuccess(createdBrandName, brandId)
      stubListWithBrand(createdBrandName, brandId)

      cy.get('#addNewProductBrandBtn_desktop_productBrandPage').filter(':visible').click()
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('be.visible')

      cy.get('#brandNameInput_addBrandDialog').type(createdBrandName)
      cy.get('#noteInput_addBrandDialog').type(note)
      cy.get('#submitNewProductBrandBtn_productBrandPage').click()

      cy.wait('@createBrand')

      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('not.exist')
      cy.get('#productBrandsTable_productBrandPage').should('contain', createdBrandName)
    })
  })

  // ------------------------------------------------------------------
  // Validation: empty brand name is blocked before submit
  // ------------------------------------------------------------------
  describe('Validation - empty brand name', () => {
    beforeEach(() => {
      cy.viewport(1280, 720)
      cy.setupApiAuthCookies()
      cy.visit('/main/inventory/product-brand')
      cy.wait(1000)

      cy.get('#addNewProductBrandBtn_desktop_productBrandPage').filter(':visible').click()
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('be.visible')
    })

    it('should show validation error when brand name is empty on submit', () => {
      // Submit without typing anything in the brand name field
      cy.get('#submitNewProductBrandBtn_productBrandPage').click()

      cy.get('#brandField_errorMessage_productBrandPage')
        .should('be.visible')
        .and('contain', 'Product brand cannot be empty')

      // Dialog should remain open (not submitted)
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('be.visible')
    })

    it('should clear validation error after typing a valid name', () => {
      // Trigger validation error first
      cy.get('#submitNewProductBrandBtn_productBrandPage').click()
      cy.get('#brandField_errorMessage_productBrandPage').should('be.visible')

      // Type a valid name — error should disappear
      cy.get('#brandNameInput_addBrandDialog').type('VALID-' + faker.string.alphanumeric(6))
      cy.get('#brandField_errorMessage_productBrandPage').should('not.exist')
    })

    // The Zod schema uses z.string().min(1) which does NOT trim whitespace.
    // A whitespace-only string has length > 0 so it passes client-side Zod validation.
    // The API rejects it server-side. This test verifies NO client-side Zod error appears.
    it('whitespace-only input → no Zod error shown, dialog stays open waiting for API response', () => {
      // Stub the API to return 400 (server rejects whitespace brand name)
      cy.intercept('POST', '/api/inventory/v1/product-brand/create', {
        statusCode: 400,
        body: {
          success: false,
          error: ['brand is required'],
        },
      }).as('createWhitespaceBrand')

      cy.get('#brandNameInput_addBrandDialog').type('   ')
      cy.get('#submitNewProductBrandBtn_productBrandPage').click()

      // Zod min(1) allows whitespace — the API call IS made (no client-side block)
      cy.wait('@createWhitespaceBrand')

      // After the API 400 error, dialog stays open (error is shown as toast)
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('be.visible')
    })
  })

  // ------------------------------------------------------------------
  // Duplicate name rejection: 409 conflict → form field error or toast
  // ------------------------------------------------------------------
  describe('Duplicate name rejection', () => {
    let existingBrandName

    before(() => {
      // Create a brand via API so it exists in the DB
      cy.setupApiAuthCookies()
      existingBrandName = 'DUP-' + faker.string.alphanumeric(10)
      cy.AddProductBrand({
        brand: existingBrandName,
        brand_status: 'active',
        note: faker.word.words(3),
      })
    })

    beforeEach(() => {
      cy.viewport(1280, 720)
      cy.setupApiAuthCookies()
      cy.visit('/main/inventory/product-brand')
      cy.wait(1000)

      cy.get('#addNewProductBrandBtn_desktop_productBrandPage').filter(':visible').click()
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('be.visible')
    })

    it('should show field error when submitting a brand name that already exists', () => {
      // Stub the create endpoint to return 409 conflict
      cy.intercept('POST', '/api/inventory/v1/product-brand/create', {
        statusCode: 409,
        body: {
          success: false,
          error: 'Brand name already exists',
        },
      }).as('createBrand')

      cy.get('#brandNameInput_addBrandDialog').type(existingBrandName)
      cy.get('#submitNewProductBrandBtn_productBrandPage').click()

      // Wait for the API response
      cy.wait('@createBrand').its('response.statusCode').should('eq', 409)

      // Dialog should remain open (not dismissed after error)
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('be.visible')

      // The component sets a field-level error for duplicate name
      cy.get('#brandField_errorMessage_productBrandPage')
        .should('be.visible')
        .and('contain', 'Brand name already exists')
    })

    it('should keep dialog open after duplicate name rejection so user can correct', () => {
      cy.intercept('POST', '/api/inventory/v1/product-brand/create', {
        statusCode: 409,
        body: {
          success: false,
          error: 'Brand name already exists',
        },
      }).as('createBrand')

      cy.get('#brandNameInput_addBrandDialog').type(existingBrandName)
      cy.get('#submitNewProductBrandBtn_productBrandPage').click()

      cy.wait('@createBrand')

      // Dialog must stay open so user can fix the name
      cy.get('#addNewProductBrandForm_desktop_productBrandPage', {
        timeout: 5000,
      }).should('be.visible')
    })

    it('should succeed after correcting the duplicate name to a unique one', () => {
      const uniqueName = 'FIXED-' + faker.string.alphanumeric(10)
      const brandId = 9003

      // First call returns 409
      cy.intercept('POST', '/api/inventory/v1/product-brand/create', {
        statusCode: 409,
        body: {
          success: false,
          error: 'Brand name already exists',
        },
      }).as('firstCreate')

      cy.get('#brandNameInput_addBrandDialog').type(existingBrandName)
      cy.get('#submitNewProductBrandBtn_productBrandPage').click()

      cy.wait('@firstCreate')

      // Dialog stays open after 409
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('be.visible')

      // Stub second call to succeed
      stubCreateSuccess(uniqueName, brandId)
      stubListWithBrand(uniqueName, brandId)

      // Clear input and type a unique name
      cy.get('#brandNameInput_addBrandDialog').clear().type(uniqueName)
      cy.get('#submitNewProductBrandBtn_productBrandPage').click()

      cy.wait('@createBrand')

      // Now it should succeed — dialog closes and new brand appears
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('not.exist')
      cy.get('#productBrandsTable_productBrandPage').should('contain', uniqueName)
    })
  })

  // ------------------------------------------------------------------
  // Dialog open/close behavior — cancel and outside click
  // ------------------------------------------------------------------
  describe('Dialog open and close behavior', () => {
    beforeEach(() => {
      cy.viewport(1280, 720)
      cy.setupApiAuthCookies()
      cy.visit('/main/inventory/product-brand')
      cy.wait(1000)
    })

    it('should open dialog when Add Product Brand button is clicked', () => {
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('not.exist')
      cy.get('#addNewProductBrandBtn_desktop_productBrandPage').filter(':visible').click()
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('be.visible')
    })

    it('should close dialog when Cancel button is clicked', () => {
      cy.get('#addNewProductBrandBtn_desktop_productBrandPage').filter(':visible').click()
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('be.visible')

      cy.get('#cancelNewProductBrandBtn_productBrandPage').click()
      cy.get('#addNewProductBrandForm_desktop_productBrandPage').should('not.exist')
    })

    // This test verifies the form reset fix in AddProductBrand.jsx:
    // onOpenChange now calls reset() when the dialog closes.
    it('should reset form fields after dialog is closed via Cancel', () => {
      cy.get('#addNewProductBrandBtn_desktop_productBrandPage').filter(':visible').click()

      cy.get('#brandNameInput_addBrandDialog').type('TEMP-NAME')
      cy.get('#cancelNewProductBrandBtn_productBrandPage').click()

      // Reopen — fields should be cleared because onOpenChange calls reset()
      cy.get('#addNewProductBrandBtn_desktop_productBrandPage').filter(':visible').click()
      cy.get('#brandNameInput_addBrandDialog').should('have.value', '')
    })
  })
})
